const input = $('Extract').first().json;
const chatInput = String(input.chatInput || '').trim();

function helpText() {
  return [
    'I can help you explore processed contacts and explain the CRM cleaning pipeline.',
    '',
    'Try:',
    '- "latest 10 contacts"',
    '- "find john@acme.com"',
    '- "search Acme"',
    '- "deliverable contacts"',
    '',
    'Notes:',
    '- Contacts are stored by Spring; I query Spring’s /api/contacts endpoint.',
  ].join('\n');
}

const lower = chatInput.toLowerCase();

// Basic intent detection
const wantsHelp = !chatInput || /^(help|\?|what can you do|commands|usage)\b/i.test(chatInput);
if (wantsHelp) {
  return [{ json: { ...input, intent: 'help', output: helpText() } }];
}

// Determine query
let q = '';
let size = 10;
let deliverableOnly = false;

const emailMatch = chatInput.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
if (emailMatch) {
  q = emailMatch[0];
} else {
  const m = chatInput.match(/\b(find|search|lookup)\b\s+(.+)$/i);
  if (m && m[2]) q = m[2].trim();
}

if (/\b(latest|recent|newest|last)\b/.test(lower)) {
  q = '';
}

if (/\b(deliverable|verified|valid)\b/.test(lower)) {
  deliverableOnly = true;
}

const sizeMatch = chatInput.match(/\b(\d{1,3})\b/);
if (sizeMatch) {
  const n = Number(sizeMatch[1]);
  if (Number.isFinite(n) && n >= 1 && n <= 50) size = n;
}

return [{ json: { ...input, intent: 'contacts', q, size, deliverableOnly } }];

const input = $json;

if (input.intent === 'help') {
  return [{ json: { output: input.output } }];
}

const springBaseUrl = String(input.springBaseUrl || '').replace(/\/+$/, '');
const url = `${springBaseUrl}/api/contacts`;

const qs = {
  q: input.q || undefined,
  deliverableOnly: Boolean(input.deliverableOnly),
  page: 0,
  size: Math.min(50, Math.max(1, Number(input.size || 10))),
};

let data;
try {
  data = await this.helpers.httpRequest({
    method: 'GET',
    url,
    qs,
    headers: { 'Accept': 'application/json' },
    json: true,
  });
} catch (e) {
  const msg = e && e.message ? e.message : String(e);
  return [{ json: { output: `I couldn’t reach the Spring backend at ${url}.\nError: ${msg}` } }];
}

const items = Array.isArray(data?.items) ? data.items : [];
if (items.length === 0) {
  return [{ json: { output: 'No contacts found for that query yet.' } }];
}

const lines = [];
lines.push(`Found ${items.length} contact(s):`);
for (const c of items) {
  const name = c.name || '(no name)';
  const email = c.email || '(no email)';
  const company = c.company ? ` — ${c.company}` : '';
  lines.push(`- ${name} <${email}>${company}`);
}

return [{ json: { output: lines.join('\n') } }];
